/**
 * @method Цельный текст разбиваем по предложениям c группировкой по 200 предлжений
 * @description Предложения обычно отделены либо \n, либо \n\n
 * @returns {index_chunk} - номер чанка
 *          {chank} - список предложенеий {} 
 */

let lineCR = '\n\n';
const MAX_CHUNKS = 200;
const chunks = [];
let current_divider = 0;
let current_chunk = [];
let index_line = 1;
if ($('Чтение файла для перевода').first().json.json.mimeType === 'text/plain') { lineCR = '\n' };
for (const item of $('Start Workflow').first().json.text.split(lineCR)) {
  if (!item.length) continue;
  current_chunk.push({index_line, item});
  index_line++;
  if (index_line % MAX_CHUNKS === 0) {
    chunks.push({ index_chunk: current_divider, chank: current_chunk });
    current_chunk = [];
    current_divider++;
  }
}
if (current_chunk.length) {
  chunks.push({ index_chunk: current_divider, chank: current_chunk });
}

return chunks;

const MAX_LINES_IN_CHUNK = 20;
const ret = [];

// нормализация масива с границами глав
const arr_chapters = $('Подготовка глав к добавлению в БД').all().reduce((acc,item) => {
  acc.push(item.json.chapter) 
  return acc.flat();
}, [])

// нормализация строк всего текста
const arr_lines = $('Разбиваем текст для структурного анализа').all().reduce((acc, item) => {
  acc.push(item.json.chank)
  return acc.flat()
}, [])

const last_chapter_number = arr_chapters.reduce((acc, item) => acc > item.chapter_number ? acc : item.chapter_number, 0);
// вставим доп запись, чтобы мы могли вставить текст от начала последней главы до конца текста
arr_chapters.push({
  chapter_number: last_chapter_number + 1,
  line: arr_lines.length + 1
})

// нарежем текст на фрагменты для перевода с учетом глав
let prev_index = -1;
let index = 0;
let chunk = '';
let prev_line = '';
for (const item of arr_chapters) {
  if (prev_index === -1) {
    prev_index = item.line;
    continue
  }

  let current_index = 0;
  chunk = '';

  for (let i=prev_index; i<item.line; i++) {
    chunk = chunk + arr_lines[i-1].item;
    current_index++;
    if (current_index > MAX_LINES_IN_CHUNK) {
      ret.push({chunk, prev_line, index_chunk: index, chapter: item.chapter_number - 1 });
      chunk = '';
      prev_line = arr_lines[i-2].item +'\n\n'+ arr_lines[i-1].item;
      index++;
      current_index = 0;
    } else chunk = chunk + '\n\n';
  }
  if (chunk.length > 0) {
    ret.push({chunk, prev_line, index_chunk: index, chapter: item.chapter_number - 1 });
    index++;
    const arr_chunk = chunk.split('\n\n').filter(item => item);
    if (arr_chunk.length > 1) prev_line = arr_chunk[arr_chunk.length-2];
    else prev_line = '';
    prev_line += `\n\n${arr_chunk[arr_chunk.length-1]}`;
  }
  prev_index = item.line;
};
return ret;

const list_chapters = $("Список глав после структурного анализа").all();
let ret = [];

list_chapters.forEach(item => {
  item.json.chapter?.length && ret.push(item.json.chapter)
})

ret = ret
  .flat()
  .sort((a,b) => a.line - b.line)
  .filter(item => item.confidence > 0.7)
  .reduce((acc, item) => {
    if (!acc.length) return [item];
    if (item.line - (acc[acc.length - 1].line) > 5) acc.push(item);
    return acc
  }, [])

if (ret.length && ret[0].line !==1) ret.unshift({chapter_number: 0, line: 1})
ret = ret.map((item, index) => ({...item, chapter_number: index + 1}));

return {chapter: ret};

